 1→use std::path::{Path, PathBuf};
 2→
 3→use clap::Args;
 4→use jj_lib::object_id::HexPrefix;
 5→use jj_lib::object_id::PrefixResolution;
 6→use jj_lib::repo::Repo;
 7→
 8→use crate::common;
 9→
10→#[derive(Args, Debug)]
11→pub struct DescArgs {
12→    /// The jj changeID (or prefix) to look up
13→    pub chid: String,
14→
15→    /// Path to jj repo (default: current directory)
16→    #[arg(long, default_value = ".")]
17→    pub repo: PathBuf,
18→}
19→
20→pub fn desc(chid: &str, repo_path: &Path) -> Result<(), Box<dyn std::error::Error>> {
21→    let (_workspace, repo) = common::load_repo(repo_path)?;
22→
23→    let prefix =
24→        HexPrefix::try_from_reverse_hex(chid).ok_or_else(|| format!("invalid changeID: {chid}"))?;
25→
26→    let resolution = repo.resolve_change_id_prefix(&prefix)?;
27→
28→    match resolution {
29→        PrefixResolution::SingleMatch(targets) => {
30→            let commit_ids = targets
31→                .into_visible()
32→                .ok_or_else(|| format!("changeID {chid} has no visible commits"))?;
33→            for commit_id in &commit_ids {
34→                let commit = repo.store().get_commit(commit_id)?;
35→                let desc = commit.description();
36→                if desc.is_empty() {
37→                    println!("(no description set)");
38→                } else {
39→                    print!("{desc}");
40→                }
41→            }
42→            Ok(())
43→        }
44→        PrefixResolution::AmbiguousMatch => {
45→            Err(format!("changeID prefix {chid} is ambiguous").into())
46→        }
47→        PrefixResolution::NoMatch => Err(format!("no commit found for changeID {chid}").into()),
48→    }
49→}
