 42→pub async fn cmd_debug_revset(
 43→    ui: &mut Ui,
 44→    command: &CommandHelper,
 45→    args: &DebugRevsetArgs,
 46→) -> Result<(), CommandError> {
 47→    let workspace_command = command.workspace_helper(ui)?;
 48→    let workspace_ctx = workspace_command.env().revset_parse_context();
 49→    let repo = workspace_command.repo().as_ref();
 50→
 51→    let mut diagnostics = RevsetDiagnostics::new();
 52→    let expression = revset::parse(&mut diagnostics, &args.revision, &workspace_ctx)?;
 53→    print_parse_diagnostics(ui, "In revset expression", &diagnostics)?;
 54→    writeln!(ui.stdout(), "-- Parsed:")?;
 55→    writeln!(ui.stdout(), "{expression:#?}")?;
 56→    writeln!(ui.stdout())?;
 57→
 58→    if args.no_resolve && args.no_optimize {
 59→        return Ok(());
 60→    } else if args.no_resolve {
 61→        let expression = revset::optimize(expression);
 62→        writeln!(ui.stdout(), "-- Optimized:")?;
 63→        writeln!(ui.stdout(), "{expression:#?}")?;
 64→        writeln!(ui.stdout())?;
 65→        return Ok(());
 66→    }
 67→
 68→    let symbol_resolver = revset_util::default_symbol_resolver(
 69→        repo,
 70→        command.revset_extensions().symbol_resolvers(),
 71→        workspace_command.id_prefix_context(),
 72→    );
 73→    let mut expression = expression.resolve_user_expression(repo, &symbol_resolver)?;
 74→    writeln!(ui.stdout(), "-- Resolved:")?;
 75→    writeln!(ui.stdout(), "{expression:#?}")?;
 76→    writeln!(ui.stdout())?;
 77→
 78→    if !args.no_optimize {
 79→        expression = revset::optimize(expression);
 80→        writeln!(ui.stdout(), "-- Optimized:")?;
 81→        writeln!(ui.stdout(), "{expression:#?}")?;
 82→        writeln!(ui.stdout())?;
 83→    }
 84→
 85→    let backend_expression = expression.to_backend_expression(repo);
